import duckdb, time, gc
from contextlib import contextmanager
DB_PATH = '/files/duckdb/siga_v1.duckdb'
@contextmanager
def db_con(path=DB_PATH, retries=5, delay=0.3):
    con = None
    for attempt in range(retries):
        try:
            con = duckdb.connect(path)
            break
        except Exception as e:
            if 'lock' in str(e).lower() and attempt < retries - 1:
                time.sleep(delay * (2 ** attempt))
            else:
                raise
    try:
        yield con
    finally:
        if con is not None:
            try: con.close()
            except Exception: pass
        gc.collect()
out=[]
with db_con() as con:
    for it in _items:
        d = it.get('json', {}) or {}
        row = con.execute("SELECT l.temp_drive_folder_id, e.final_drive_folder_id, e.final_drive_folder_path FROM equipment_ingestion_log l LEFT JOIN equipment e ON e.ingestion_id = l.ingestion_id WHERE l.ingestion_id = ? ORDER BY l.updated_at DESC NULLS LAST LIMIT 1", [d.get('ingestion_id')]).fetchone()
        temp_id = row[0] if row else None
        final_id = row[1] if row else None
        final_path = row[2] if row else None
        out.append({'json': {**d, 'existing_temp_drive_folder_id': temp_id, 'existing_final_drive_folder_id': final_id, 'existing_final_drive_folder_path': final_path}, **(({'binary': it.get('binary')} if it.get('binary') else {}))})
return out

