function classifyByTaxonomy(subtypeStr, labelStr, blobStr) {
  const norm = (s) => String(s || '').toLowerCase().normalize('NFD').replace(/[\u0300-\u036f]/g, '').replace(/\s+/g, ' ').trim();
  const search = norm(blobStr) + ' ' + norm(subtypeStr) + ' ' + norm(labelStr);
  const sorted = Object.keys(SIGA_TAXONOMY).sort((a, b) => b.length - a.length);
  for (const key of sorted) {
    const k = norm(key);
    if (k && (search === k || search.includes(' ' + k + ' ') || search.startsWith(k + ' ') || search.endsWith(' ' + k) || search.includes(k))) {
      return SIGA_TAXONOMY[key];
    }
  }
  return null;
}
