function clean(v) {
  return String(v ?? '').replace(/\s+/g, ' ').trim();
}
function lower(v) {
  return clean(v).toLowerCase();
}
function toTitleCase(value) {
  const s = clean(value);
  if (!s) return '';
  if (/^[A-Z0-9 ._-]+$/.test(s)) return s;
  return s
    .split(' ')
    .map(part => part ? part.charAt(0).toUpperCase() + part.slice(1).toLowerCase() : part)
    .join(' ');
}
function normalizeBrand(value) {
  const s = clean(value);
  if (!s) return '';
  if (/^hilti$/i.test(s)) return 'Hilti';
  return toTitleCase(s);
}
function normalizeModel(value) {
  let s = clean(value).replace(/\s+/g, ' ');
  if (!s) return '';
  s = s.replace(/^gx[-\s]?120$/i, 'GX 120');
  s = s.replace(/^gc[-\s]?22$/i, 'GC 22');
  s = s.replace(/^x[-\s]?120\s*nph$/i, 'X-120 NPH');
  return s.toUpperCase() === s ? s : s;
}
function collapseRepeatedLabel(value) {
  const s = clean(value);
  if (!s) return '';
  const repeated = s.match(/^(.+?)\s+\1$/i);
  if (repeated) return clean(repeated[1]);
  return s;
}
function uniqBy(arr, fn) {
  const out = [];
  const seen = new Set();
  for (const item of arr || []) {
    const key = fn(item);
    if (seen.has(key)) continue;
    seen.add(key);
    out.push(item);
  }
  return out;
}
function uniqStrings(arr) {
  return [...new Set((arr || []).map(v => clean(v)).filter(Boolean))];
}
function normCondition(value) {
  const s = clean(value);
  if (!s) return '';
  const fr = s
    .replace(/Used - good working condition apparent, normal wear and soiling/gi, 'bon état d’usage, usure normale et salissures visibles')
    .replace(/^used$/i, 'usagé')
    .replace(/^good$/i, 'bon état')
    .replace(/partially used or new/gi, 'partiellement utilisée')
    .replace(/partiellement utilisée ou nouvelle/gi, 'partiellement utilisée')
    .replace(/bon état apparent/gi, 'bon état apparent');
  return clean(fr);
}
function normItemRole(item) {
  const blob = lower([
    item.item_role,
    item.classification,
    item.detected_object_type,
    item.subtype,
    item.raw_label,
    item.label,
    item.model
  ].filter(Boolean).join(' '));
  if (/(gc\s*22|fuel cartridge|cartouche[s]? de? gaz|cartouches? à gaz|consommable)/i.test(blob)) return 'consumable';
  if (/(x[-\s]?120\s*nph|embout|piston|adaptateur|accessoire|magazine)/i.test(blob)) return 'accessory';
  if (/(coffret|mallette|carrying case|hard carrying case|transport case|bo[iî]te de transport|packaging)/i.test(blob)) return 'packaging';
  if (/(notice|documentation|manual)/i.test(blob)) return 'associated_item';
  return item.item_role || item.classification || 'associated_item';
}
function normSubtype(item) {
  const blob = lower([
    item.detected_object_type,
    item.subtype,
    item.raw_label,
    item.label,
    item.model
  ].filter(Boolean).join(' '));
  if (/(gc\s*22|fuel cartridge|cartouche[s]? de? gaz|cartouches? à gaz)/i.test(blob)) return 'cartouche de gaz';
  if (/(x[-\s]?120\s*nph|embout|piston|adaptateur)/i.test(blob)) return 'embout / piston de fixation';
  if (/(coffret|mallette|carrying case|hard carrying case|transport case)/i.test(blob)) return 'coffret de transport';
  if (/(notice|documentation|manual)/i.test(blob)) return 'notice / documentation';
  if (/(magazine accessory|nail strip)/i.test(blob)) return 'chargeur / magasin';
  return collapseRepeatedLabel(clean(item.subtype || item.detected_object_type || item.raw_label || item.label));
}
function normLabel(item, subtype, role) {
  if (role === 'consumable') {
    const model = normalizeModel(item.model);
    return model ? `${subtype} ${model}` : subtype;
  }
  const brand = normalizeBrand(item.brand);
  const model = normalizeModel(item.model);
  if (role === 'packaging' && brand) return `${subtype} ${brand}`;
  if (role === 'accessory' && model) return `${subtype} ${model}`;
  if (brand && model && /notice/.test(lower(subtype))) return `${subtype} ${brand} ${model}`;
  return subtype;
}
function normalizeAssociatedItem(item) {
  const role = normItemRole(item);
  const subtype = normSubtype(item);
  const brand = normalizeBrand(item.brand);
  let model = normalizeModel(item.model);
  const blob = lower([item.detected_object_type, item.subtype, item.label, item.raw_label, item.model].filter(Boolean).join(' '));
  if (!model && /gc\s*22/.test(blob)) model = 'GC 22';
  if (!model && /x[-\s]?120\s*nph/.test(blob)) model = 'X-120 NPH';
  const label = normLabel(item, subtype, role);
  const condition_notes = uniqStrings((item.condition_notes || []).map(normCondition));
  const item_condition = normCondition(item.item_condition);
  return {
    ...item,
    classification: role === 'consumable' ? 'consumable' : (role === 'accessory' ? 'accessory' : (role === 'packaging' ? 'packaging' : 'associated_item')),
    item_role: role,
    detected_object_type: subtype,
    subtype,
    brand,
    model,
    label,
    raw_label: collapseRepeatedLabel(clean(item.raw_label || item.detected_object_type || item.label || subtype)),
    condition_notes,
    item_condition,
    is_consumable: role === 'consumable',
    is_accessory: role === 'accessory',
    consumable_state: role === 'consumable' ? (clean(item.consumable_state) || 'used') : (clean(item.consumable_state) || 'unknown'),
    packaging_detected: role === 'packaging' ? true : Boolean(item.packaging_detected),
