if (uploaded.error || uploaded.message) errors.push({ code: 'document_upload_failed', detail: uploaded.error || uploaded.message });
const doc = linked.current_document || {};
const actualName = uploaded.name || linked.final_drive_name || doc.final_drive_name || linked.original_filename || doc.original_filename || null;
return [{
  json: {
    document_id: linked.document_id || doc.document_id || null,
    document_index: linked.document_index || doc.document_index || null,
    original_filename: linked.original_filename || doc.original_filename || null,
    mime_type: uploaded.mimeType || linked.mime_type || doc.mime_type || 'application/octet-stream',
    document_type: linked.document_type || doc.document_type || 'standard',
    final_drive_name: actualName,
    final_drive_file_id: uploaded.id || null,
    final_drive_web_view_link: uploaded.webViewLink || null,
    final_drive_path: linked.final_drive_path || doc.final_drive_path || null,
    processing_status: uploaded.id ? (errors.length ? 'finalized_partial_error' : 'finalized') : 'finalization_failed',
    error_json: errors.length ? errors : null,
    // Champs facture
    is_invoice: (linked.document_type || doc.document_type) === 'invoice',
    invoice_data: doc.invoice_data || null,
    vendor_name: doc.vendor_name || null,
    invoice_date: doc.invoice_date || null,
    invoice_number: doc.invoice_number || null,
    amount_ht: doc.amount_ht ?? null,
    amount_ttc: doc.amount_ttc ?? null,
    currency: doc.currency || null,
    vat_rate: doc.vat_rate ?? null,
    warranty_duration_months: doc.warranty_duration_months ?? null,
    payment_method: doc.payment_method || null,
    invoice_confidence: doc.invoice_confidence ?? 0
  }
}];

return $input.all().map(item => {
  const j = item.json || {};
  return {
    json: {
      document_id: j.document_id || null,
      document_index: j.document_index || null,
      original_filename: j.original_filename || null,
      mime_type: j.mime_type || 'application/octet-stream',
      final_drive_name: j.final_drive_name || j.original_filename || null,
      final_drive_file_id: null,
      final_drive_web_view_link: null,
      final_drive_path: j.final_drive_path || null,
      processing_status: 'finalization_failed',
      error_json: [{ code: 'missing_document_binary', message: 'Document binary could not be resolved for upload' }]
    }
  };
});

const doc = $json.current_document || {};
const filename = String(doc.filename || doc.original_filename || '').toLowerCase();
const mime = String(doc.mime_type || '').toLowerCase();
const messageText = String($json.message?.text || '').toLowerCase();
const invoiceKeywords = ['facture', 'invoice', 'fact_', 'receipt', 'recu', 'reçu', 'bon_commande', 'bon commande', 'devis', 'ticket_caisse', 'ticket caisse'];
const isInvoiceByName = invoiceKeywords.some(k => filename.includes(k));
const isInvoiceByContext = invoiceKeywords.some(k => messageText.includes(k));
const isPdf = mime === 'application/pdf' || filename.endsWith('.pdf');
const isImageDoc = /^image\//.test(mime) && (isInvoiceByName || isInvoiceByContext);
const document_type = (isInvoiceByName || (isPdf && isInvoiceByContext) || isImageDoc) ? 'invoice' : (isPdf ? 'pdf_document' : 'standard');
const should_analyze_invoice = document_type === 'invoice';
return [{ json: {
  ...$json,
  document_type,
  should_analyze_invoice,
  current_document: { ...doc, document_type, should_analyze_invoice }
} }];

