={{
(function() {
  const mime = $binary?.data?.mimeType || 'image/jpeg';
  const data = $binary?.data?.data || '';
  const isImage = /^image\//.test(mime);
  const doc = $json.current_document || {};
  const msgText = $json.message?.text || '';
  const prompt = "Extrait les données de facturation de ce document. Réponds UNIQUEMENT avec ce JSON strict, sans markdown :\n{\"vendor_name\":\"\",\"invoice_date\":\"YYYY-MM-DD ou null\",\"invoice_number\":\"\",\"amount_ht\":null,\"amount_ttc\":null,\"currency\":\"EUR\",\"vat_rate\":null,\"payment_method\":\"\",\"warranty_duration_months\":null,\"notes\":\"\",\"confidence\":0.0}\nSi une information est absente, laisse null ou vide. Mets confidence entre 0 et 1.";
  const contentArr = [];
  if (isImage && data) {
    contentArr.push({ type: 'image', source: { type: 'base64', media_type: mime, data: data } });
  }
  contentArr.push({ type: 'text', text: (msgText ? 'Contexte message : ' + msgText + '\n' : '') + prompt });
  return {
    model: 'claude-sonnet-4-6',
    max_tokens: 512,
    system: "Tu es un extracteur de données de facturation. Analyse le document fourni et extrait les informations financières clés. Réponds UNIQUEMENT avec un JSON valide, sans markdown, sans explication.",
    messages: [{ role: 'user', content: contentArr }]
  };
})()
}}

parameters.jsCode:
let upstream = {};
try { upstream = $('If Is Invoice Document').item?.json || {}; } catch {}
if (!upstream || !upstream.ingestion_id) {
  try { upstream = $('Detect Invoice Type').item?.json || {}; } catch {}
}
const response = $json || {};
let invoiceData = null;
try {
  const text = (response.content || []).map(c => c.text || '').join('');
  const cleaned = text.replace(/^```json\s*/i, '').replace(/```$/i, '').trim();
  if (cleaned.startsWith('{')) invoiceData = JSON.parse(cleaned);
} catch {}
const doc = upstream.current_document || {};
const enrichedDoc = {
  ...doc,
  invoice_data: invoiceData,
  vendor_name: invoiceData?.vendor_name || null,
  invoice_date: invoiceData?.invoice_date !== 'YYYY-MM-DD ou null' ? invoiceData?.invoice_date || null : null,
  invoice_number: invoiceData?.invoice_number || null,
  amount_ht: invoiceData?.amount_ht ?? null,
  amount_ttc: invoiceData?.amount_ttc ?? null,
  currency: invoiceData?.currency || 'EUR',
  vat_rate: invoiceData?.vat_rate ?? null,
  warranty_duration_months: invoiceData?.warranty_duration_months ?? null,
  payment_method: invoiceData?.payment_method || null,
  invoice_notes: invoiceData?.notes || null,
  invoice_confidence: invoiceData?.confidence ?? 0
};
return [{ json: { ...upstream, invoice_data: invoiceData, invoice_extracted: !!invoiceData, current_document: enrichedDoc }, binary: $binary }];

// Agrège toutes les images uploadées + récupère les binaires depuis Prepare Binary Inline
// Ce nœud reçoit les résultats de Upload Temp to Drive (N items, un par image)
// Il produit UN SEUL item avec :
//   - tous les binaires (data, data1, data2...) pour le nœud LangChain
//   - le contexte JSON complet (message_facts, Drive metadata, skeleton draft)

const driveItems = $input.all();
const binaryItems = (() => { try { return $('Prepare Binary Inline').all(); } catch { return []; } })();
const root = (() => { try { return $('Attach Temp Folder Context').first().json || {}; } catch { return {}; } })();
const messageFacts = root.message_facts || {};
const images = Array.isArray(root.images) ? root.images : [];

// Construire le mapping Drive par index
const driveByIndex = new Map();
driveItems.forEach((item, i) => {
  const j = item.json || {};
  const idx = Number(j.image_index || j.current_image?.index || i + 1);
  driveByIndex.set(idx, j);
});

// Construire le mapping binaire par index
const binaryByIndex = new Map();
binaryItems.forEach((item, i) => {
  const j = item.json || {};
  const idx = Number(j.image_index || j.current_image?.index || i + 1);
  binaryByIndex.set(idx, item.binary || {});
});

// Construire les métadonnées par image
const imagesMetadata = images.map((img, i) => {
  const imageIndex = Number(img.index || i + 1);
  const imageUid = String(root.ingestion_id || 'SIGA') + '-IMG' + String(imageIndex).padStart(3, '0');
  const drive = driveByIndex.get(imageIndex) || {};
  return {
    image_index: imageIndex,
    image_uid: imageUid,
    original_filename: img.filename || drive.name || `image_${imageIndex}.jpg`,
    mime_type: img.mime_type || 'image/jpeg',
    binary_key: imageIndex === 1 ? 'data' : `data${imageIndex - 1}`,
    temp_drive_file_id: drive.id || null,
    temp_drive_web_view_link: drive.webViewLink || null,
    temp_drive_file_name: drive.name || img.filename || null,
    temp_drive_folder_id: root.temp_drive_folder_id || null
  };
});

// Agréger les binaires sur UN SEUL item
const mergedBinary = {};
imagesMetadata.forEach(meta => {
  const binaries = binaryByIndex.get(meta.image_index) || {};
  const firstBinaryKey = Object.keys(binaries)[0];
  if (firstBinaryKey) {
    mergedBinary[meta.binary_key] = binaries[firstBinaryKey];
  }
});

// Skeleton equipment_draft_v2 (sera enrichi par Apply Final Consolidation)
// equipment_id : cohérent avec l'ancienne convention Build Draft v2
const equipment_id = root.ingestion_id ? root.ingestion_id + '-EQ1' : 'SIGA-' + Date.now() + '-EQ1';

const equipment_draft_v2 = {
  equipment: {
    equipment_id,
    label: '',
    category: '',
    subtype: '',
    brand: '',
    model: '',
    serial_number: null,
    condition: '',
    location: String(messageFacts.location_hint || ''),
    acquisition_mode: String(messageFacts.ownership_mode || ''),
    purchase_price: messageFacts.purchase_price || null,
    purchase_currency: messageFacts.purchase_currency || 'EUR',
    acquisition_note: String(messageFacts.acquisition_note || ''),
    usage_notes: String(messageFacts.usage_notes || ''),
    associated_items: [],
    consumables: [],
    accessories: []
  },
  media: imagesMetadata.map(m => ({
    media_id: (root.ingestion_id || 'SIGA-' + Date.now()) + '-IMG' + String(m.image_index),
    image_index: m.image_index,
    image_uid: m.image_uid,
    original_filename: m.original_filename,
    mime_type: m.mime_type,
    image_role: 'unknown',
    temp_drive_file_id: m.temp_drive_file_id,
    temp_drive_web_view_link: m.temp_drive_web_view_link,
    temp_drive_file_name: m.temp_drive_file_name,
    temp_drive_folder_id: m.temp_drive_folder_id
  })),
  validation: {
    review_required: false,
    review_reasons: [],
    missing_fields: []
  },
  business_context: {
    message_text: String(root.message_text || root.raw_text || ''),
    message_facts: messageFacts,
    ingestion_id: String(root.ingestion_id || ''),
    ingestion_date: String(root.ingestion_date || ''),
    images_count: imagesMetadata.length
  }
};

return [{
  json: {
    ...root,
    equipment_id,
    equipment_draft_v2,
    images_metadata: imagesMetadata,
    images_count: imagesMetadata.length,
    // Contexte LLM : message utilisateur + facts structurés
    vision_context: {
      message_text: String(root.message_text || root.raw_text || ''),
      message_facts: messageFacts,
      images_count: imagesMetadata.length,
      images_metadata: imagesMetadata
    }
  },
  binary: mergedBinary
}];
